"""Async `AsyncCursor` namespace + nested sub-namespaces.

Mirror of `_cursor.Cursor` for the async surface. Sub-namespaces
(`models`, `repositories`) are nested classes carrying static-method
dispatchers — the cleaner shape that the async greenfield can adopt
without inheriting the sync side's instance-attribute pattern.
"""

from __future__ import annotations

from typing import TYPE_CHECKING

from .types import SDKModel, SDKRepository, SDKUser

if TYPE_CHECKING:
    from ._async_client import AsyncClient


class AsyncCursor:
    """Top-level catalog namespace for async users.

    Sub-namespaces (`models`, `repositories`) are nested classes with
    static-method dispatchers. The sync `Cursor` was implemented as
    instance-attribute assignment (`Cursor.models = _CursorModels()`)
    for historical reasons; the async surface uses the cleaner pattern
    so future namespaces don't have to introduce a private class plus
    a singleton instance just to hold one method.
    """

    @classmethod
    async def me(cls, *, client: "AsyncClient", api_key: str | None = None) -> SDKUser:
        return await client.me(api_key=api_key)

    class models:
        @staticmethod
        async def list(
            *, client: "AsyncClient", api_key: str | None = None
        ) -> list[SDKModel]:
            return await client.list_models(api_key=api_key)

    class repositories:
        @staticmethod
        async def list(
            *, client: "AsyncClient", api_key: str | None = None
        ) -> list[SDKRepository]:
            return await client.list_repositories(api_key=api_key)
